using System;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth;
    
    public int currency = 500;
}

public class DamageCalculation : MonoBehaviour
{
    private void OnCollisionEnter(Collision collision) 
    {
        var player = FindObjectOfType<PlayerStats>();
        
        if (collision.gameObject.CompareTag("Enemy")) 
        {
            // Assuming enemies have a "Damage" property for how much they deal in damage
            int damageDealt = collision.gameObject.GetComponent<EnemyScript>().damage;
            
            player.currentHealth -= damageDealt;
        } 
    }
}

public class ShopPurchases : MonoBehaviour
{
    private PlayerStats player;
    
    void Start() 
    {
        player = FindObjectOfType<PlayerStats>();
    }
    
    public void BuyItem(int itemCost) 
    {
        if (player.currency >= itemCost) 
        {
            // Implement your actual logic for buying an item here
            
            player.currency -= itemCost;
        } 
    }
}